using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers;

public static class TestHelpers
{
    public static SchoolContext CreateInMemoryContext(string? dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    public static void SeedStudents(SchoolContext context)
    {
        context.Students.AddRange(
            new Student { ID = 1, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
            new Student { ID = 2, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
            new Student { ID = 3, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") }
        );
        context.SaveChanges();
    }

    public static void SeedDepartments(SchoolContext context)
    {
        context.Departments.AddRange(
            new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01") },
            new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01") }
        );
        context.SaveChanges();
    }

    public static void SeedInstructors(SchoolContext context)
    {
        context.Instructors.AddRange(
            new Instructor { ID = 10, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11"), CourseAssignments = new List<CourseAssignment>() },
            new Instructor { ID = 11, FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = DateTime.Parse("2002-07-06"), CourseAssignments = new List<CourseAssignment>() }
        );
        context.SaveChanges();
    }

    public static void SeedCourses(SchoolContext context)
    {
        if (!context.Departments.Any())
            SeedDepartments(context);

        context.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2 }
        );
        context.SaveChanges();
    }

    public static void SeedFullData(SchoolContext context)
    {
        SeedInstructors(context);
        SeedDepartments(context);
        SeedCourses(context);
        SeedStudents(context);

        context.Enrollments.AddRange(
            new Enrollment { EnrollmentID = 1, StudentID = 1, CourseID = 1050, Grade = Grade.A },
            new Enrollment { EnrollmentID = 2, StudentID = 2, CourseID = 4022, Grade = Grade.B }
        );
        context.SaveChanges();
    }
}

using ContosoUniversity;

namespace ContosoUniversity.Tests.Models;

public class PaginatedListTests
{
    [Fact]
    public void Constructor_SetsPageIndex()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 2, 3);

        // Assert
        Assert.Equal(2, list.PageIndex);
    }

    [Fact]
    public void Constructor_CalculatesTotalPages()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 1, 3);

        // Assert
        Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
    }

    [Fact]
    public void Constructor_AddsItemsToList()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var list = new PaginatedList<string>(items, 3, 1, 10);

        // Assert
        Assert.Equal(3, list.Count);
        Assert.Equal("a", list[0]);
        Assert.Equal("b", list[1]);
        Assert.Equal("c", list[2]);
    }

    [Theory]
    [InlineData(10, 3, 4)]  // ceil(10/3) = 4
    [InlineData(9, 3, 3)]   // ceil(9/3) = 3
    [InlineData(1, 10, 1)]  // ceil(1/10) = 1
    [InlineData(0, 5, 0)]   // ceil(0/5) = 0
    [InlineData(100, 10, 10)]
    public void TotalPages_CalculatesCorrectly(int count, int pageSize, int expectedTotalPages)
    {
        var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);
        Assert.Equal(expectedTotalPages, list.TotalPages);
    }

    [Theory]
    [InlineData(1, false)]  // page 1 has no previous
    [InlineData(2, true)]   // page 2 has previous
    [InlineData(3, true)]
    public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
    {
        var list = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);
        Assert.Equal(expected, list.HasPreviousPage);
    }

    [Theory]
    [InlineData(1, 3, true)]   // page 1 of 3 has next
    [InlineData(3, 3, false)]  // page 3 of 3 has no next
    [InlineData(2, 3, true)]
    public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
    {
        var list = new PaginatedList<int>(new List<int>(), totalPages * 5, pageIndex, 5);
        Assert.Equal(expected, list.HasNextPage);
    }

    [Fact]
    public void Create_ReturnsCorrectPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 30).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.Equal(2, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.Equal(10, result.Count);
        Assert.Equal(11, result[0]); // second page starts at 11
        Assert.Equal(20, result[9]);
    }

    [Fact]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(1, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.Equal(10, result.Count);
        Assert.Equal(1, result[0]);
    }

    [Fact]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var result = PaginatedList<int>.Create(source, 3, 10);

        Assert.Equal(3, result.PageIndex);
        Assert.Equal(5, result.Count); // 25 - 20 = 5
        Assert.Equal(21, result[0]);
    }

    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Empty(result);
        Assert.Equal(0, result.TotalPages);
    }
}

using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models;

public class PersonModelTests
{
    [Fact]
    public void FullName_ReturnsLastNameCommaFirstName()
    {
        // Arrange
        var student = new Student { FirstMidName = "Carson", LastName = "Alexander" };

        // Act
        var fullName = student.FullName;

        // Assert
        Assert.Equal("Alexander, Carson", fullName);
    }

    [Fact]
    public void FullName_Instructor_ReturnsLastNameCommaFirstName()
    {
        var instructor = new Instructor { FirstMidName = "Kim", LastName = "Abercrombie" };
        Assert.Equal("Abercrombie, Kim", instructor.FullName);
    }

    [Fact]
    public void Student_EnrollmentDate_CanBeSet()
    {
        var date = new DateTime(2020, 9, 1);
        var student = new Student { EnrollmentDate = date };
        Assert.Equal(date, student.EnrollmentDate);
    }

    [Fact]
    public void Instructor_HireDate_CanBeSet()
    {
        var date = new DateTime(2000, 1, 15);
        var instructor = new Instructor { HireDate = date };
        Assert.Equal(date, instructor.HireDate);
    }
}

public class ErrorViewModelTests
{
    [Fact]
    public void ShowRequestId_ReturnsFalse_WhenRequestIdIsNull()
    {
        var model = new ErrorViewModel { RequestId = null };
        Assert.False(model.ShowRequestId);
    }

    [Fact]
    public void ShowRequestId_ReturnsFalse_WhenRequestIdIsEmpty()
    {
