using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _service;

    public NotificationServiceTests()
    {
        _service = new NotificationService();
        // Drain any existing notifications from the static queue
        while (_service.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        while (_service.ReceiveNotification() != null) { }
        _service.Dispose();
    }

    [Fact]
    public void SendNotification_WithDisplayName_EnqueuesNotification()
    {
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Contains("Student 'John Doe'", notification.Message);
        Assert.Contains("created", notification.Message);
        Assert.Equal("Admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Course", "42", null, EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("(ID: 42)", notification.Message);
        Assert.Contains("updated", notification.Message);
    }

    [Fact]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_TwoParamOverload_Works()
    {
        _service.SendNotification("Student", "5", EntityOperation.DELETE);
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("5", notification.EntityId);
        Assert.Equal("DELETE", notification.Operation);
        Assert.Contains("deleted", notification.Message);
    }

    [Theory]
    [InlineData(EntityOperation.CREATE, "created")]
    [InlineData(EntityOperation.UPDATE, "updated")]
    [InlineData(EntityOperation.DELETE, "deleted")]
    public void SendNotification_GeneratesCorrectMessage_ForOperation(EntityOperation operation, string expectedVerb)
    {
        _service.SendNotification("Department", "1", "Engineering", operation);
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains(expectedVerb, notification.Message);
    }

    [Fact]
    public void ReceiveNotification_ReturnsNull_WhenQueueEmpty()
    {
        var result = _service.ReceiveNotification();
        Assert.Null(result);
    }

    [Fact]
    public void ReceiveNotification_ReturnsNotificationsInOrder()
    {
        _service.SendNotification("A", "1", "First", EntityOperation.CREATE);
        _service.SendNotification("B", "2", "Second", EntityOperation.UPDATE);

        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();

        Assert.Equal("A", first!.EntityType);
        Assert.Equal("B", second!.EntityType);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        var exception = Record.Exception(() => _service.MarkAsRead(1));
        Assert.Null(exception);
    }

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();
        var exception = Record.Exception(() => service.Dispose());
        Assert.Null(exception);
    }

    [Fact]
    public void SendNotification_WithEmptyDisplayName_UsesIdFormat()
    {
        _service.SendNotification("Student", "99", "", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("(ID: 99)", notification.Message);
    }

    [Fact]
    public void SendNotification_WithWhitespaceDisplayName_UsesIdFormat()
    {
        _service.SendNotification("Student", "99", "   ", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("(ID: 99)", notification.Message);
    }

    [Fact]
    public void SendNotification_SetsCreatedAt()
    {
        var before = DateTime.Now;
        _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
        var after = DateTime.Now;

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.InRange(notification.CreatedAt, before, after);
    }

    [Fact]
    public void SendNotification_CreateMessage_IncludesNew()
    {
        _service.SendNotification("Student", "1", "John", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.StartsWith("New", notification.Message);
    }

    [Fact]
    public void SendNotification_DeleteMessage_IncludesDeleted()
    {
        _service.SendNotification("Course", "42", "Chemistry", EntityOperation.DELETE);
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Course 'Chemistry' has been deleted", notification.Message);
    }

    [Fact]
    public void SendNotification_UpdateMessage_IncludesUpdated()
    {
        _service.SendNotification("Department", "1", "Math", EntityOperation.UPDATE);
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Department 'Math' has been updated", notification.Message);
    }
}

