using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers;

public static class TestHelpers
{
    public static SchoolContext CreateInMemoryContext(string? dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    public static void SeedStudents(SchoolContext context)
    {
        context.Students.AddRange(
            new Student { ID = 1, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
            new Student { ID = 2, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
            new Student { ID = 3, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") }
        );
        context.SaveChanges();
    }

    public static void SeedDepartments(SchoolContext context)
    {
        context.Departments.AddRange(
            new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01") },
            new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01") }
        );
        context.SaveChanges();
    }

    public static void SeedInstructors(SchoolContext context)
    {
        context.Instructors.AddRange(
            new Instructor { ID = 10, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11"), CourseAssignments = new List<CourseAssignment>() },
            new Instructor { ID = 11, FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = DateTime.Parse("2002-07-06"), CourseAssignments = new List<CourseAssignment>() }
        );
        context.SaveChanges();
    }

    public static void SeedCourses(SchoolContext context)
    {
        if (!context.Departments.Any())
            SeedDepartments(context);

        context.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2 }
        );
        context.SaveChanges();
    }

    public static void SeedFullData(SchoolContext context)
    {
        SeedInstructors(context);
        SeedDepartments(context);
        SeedCourses(context);
        SeedStudents(context);

        context.Enrollments.AddRange(
            new Enrollment { EnrollmentID = 1, StudentID = 1, CourseID = 1050, Grade = Grade.A },
            new Enrollment { EnrollmentID = 2, StudentID = 2, CourseID = 4022, Grade = Grade.B }
        );
        context.SaveChanges();
    }
}

