using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class HomeControllerTests : IDisposable
{
    private readonly HomeController _controller;
    private readonly Data.SchoolContext _context;

    public HomeControllerTests()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new HomeController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_ReturnsViewResult()
    {
        var result = _controller.Index();
        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void About_ReturnsViewResult_WithEnrollmentDateGroups()
    {
        TestHelpers.SeedStudents(_context);
        var result = _controller.About();
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(viewResult.Model);
        Assert.NotEmpty(model);
    }

    [Fact]
    public void About_NoStudents_ReturnsEmptyList()
    {
        var result = _controller.About();
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(viewResult.Model);
        Assert.Empty(model);
    }

    [Fact]
    public void About_GroupsByEnrollmentDate()
    {
        _context.Students.AddRange(
            new Student { FirstMidName = "A", LastName = "A", EnrollmentDate = DateTime.Parse("2020-09-01") },
            new Student { FirstMidName = "B", LastName = "B", EnrollmentDate = DateTime.Parse("2020-09-01") },
            new Student { FirstMidName = "C", LastName = "C", EnrollmentDate = DateTime.Parse("2021-09-01") }
        );
        _context.SaveChanges();

        var result = _controller.About();
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(viewResult.Model);
        Assert.Equal(2, model.Count);
        Assert.Contains(model, g => g.StudentCount == 2);
        Assert.Contains(model, g => g.StudentCount == 1);
    }

    [Fact]
    public void Contact_ReturnsViewResult_WithMessage()
    {
        var result = _controller.Contact();
        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.Equal("Your contact page.", _controller.ViewBag.Message);
    }

    [Fact]
    public void Error_ReturnsViewResult()
    {
        var result = _controller.Error();
        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Unauthorized_ReturnsViewResult_WithMessage()
    {
        var result = _controller.Unauthorized();
        Assert.IsType<ViewResult>(result);
        Assert.Equal("You don't have permission to access this resource.", _controller.ViewBag.Message);
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly StudentsController _controller;
    private readonly SchoolContext _context;

    public StudentsControllerTests()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new StudentsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    #region Index

    [Fact]
    public void Index_ReturnsViewResult_WithPaginatedList()
    {
        TestHelpers.SeedStudents(_context);
        var result = _controller.Index(null, null, null, null);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(3, model.Count);
    }

    [Fact]
    public void Index_DefaultSort_OrdersByLastName()
    {
        TestHelpers.SeedStudents(_context);
        var result = _controller.Index(null, null, null, null);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Alexander", model[0].LastName);
        Assert.Equal("Alonso", model[1].LastName);
        Assert.Equal("Anand", model[2].LastName);
    }

    [Fact]
    public void Index_NameDesc_OrdersByLastNameDescending()
    {
        TestHelpers.SeedStudents(_context);
        var result = _controller.Index("name_desc", null, null, null);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Anand", model[0].LastName);
    }

    [Fact]
    public void Index_DateSort_OrdersByEnrollmentDate()
    {
        TestHelpers.SeedStudents(_context);
        var result = _controller.Index("Date", null, null, null);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Alexander", model[0].LastName); // 2010
    }

    [Fact]
    public void Index_DateDescSort_OrdersByDateDescending()
    {
        TestHelpers.SeedStudents(_context);
        var result = _controller.Index("date_desc", null, null, null);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Anand", model[0].LastName); // 2013
    }

    [Fact]
    public void Index_SearchString_FiltersStudents()
    {
        TestHelpers.SeedStudents(_context);
        var result = _controller.Index(null, null, "Alexander", null);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
        Assert.Equal("Alexander", model[0].LastName);
    }

    [Fact]
    public void Index_SearchByFirstName_FiltersStudents()
    {
        TestHelpers.SeedStudents(_context);
        var result = _controller.Index(null, null, "Carson", null);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
        Assert.Equal("Carson", model[0].FirstMidName);
    }

    [Fact]
    public void Index_NewSearchString_ResetsPageTo1()
    {
        TestHelpers.SeedStudents(_context);
        var result = _controller.Index(null, null, "A", null);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(1, model.PageIndex);
    }

    [Fact]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        TestHelpers.SeedStudents(_context);
        var result = _controller.Index(null, "Alexander", null, null);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
    }

    [Fact]
    public void Index_SetsViewBagSortParms()
    {
        TestHelpers.SeedStudents(_context);
        _controller.Index(null, null, null, null);
        Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
        Assert.Equal("Date", _controller.ViewBag.DateSortParm);
    }

    [Fact]
    public void Index_WithSortOrder_SetsCorrectSortParms()
    {
        TestHelpers.SeedStudents(_context);
        _controller.Index("Date", null, null, null);
        Assert.Equal("", _controller.ViewBag.NameSortParm);
        Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
    }

    [Fact]
    public void Index_EmptyDatabase_ReturnsEmptyPaginatedList()
    {
        var result = _controller.Index(null, null, null, null);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Empty(model);
    }

    #endregion

    #region Details

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        _context.Students.Add(new Student
        {
            ID = 1, FirstMidName = "Carson", LastName = "Alexander",
            EnrollmentDate = DateTime.Parse("2020-01-01"),
            Enrollments = new List<Enrollment>()
        });
        _context.SaveChanges();

        var result = _controller.Details(1);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal("Carson", model.FirstMidName);
        Assert.Equal("Alexander", model.LastName);
    }

    #endregion

    #region Create GET

    [Fact]
    public void Create_Get_ReturnsViewResult_WithStudentModel()
    {
        var result = _controller.Create();
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal(DateTime.Today, model.EnrollmentDate);
    }

    #endregion

    #region Create POST

    [Fact]
    public void CreatePost_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            FirstMidName = "Test", LastName = "Student",
            EnrollmentDate = new DateTime(2020, 9, 1)
        };

        var result = _controller.Create(student);
        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.Single(_context.Students);
    }

    [Fact]
    public void CreatePost_InvalidDate_MinValue_ReturnsView()
    {
        var student = new Student
        {
            FirstMidName = "Test", LastName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Create(student);
        Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void CreatePost_InvalidDate_TooOld_ReturnsView()
    {
        var student = new Student
        {
            FirstMidName = "Test", LastName = "Student",
            EnrollmentDate = new DateTime(1752, 12, 31)
        };

        var result = _controller.Create(student);
        Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void CreatePost_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            FirstMidName = "Test",
            EnrollmentDate = new DateTime(2020, 9, 1)
        };

        var result = _controller.Create(student);
        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void CreatePost_SavesStudentToDatabase()
    {
        var student = new Student
        {
            FirstMidName = "Jane", LastName = "Doe",
            EnrollmentDate = new DateTime(2021, 1, 15)
        };

        _controller.Create(student);

        var saved = _context.Students.First();
        Assert.Equal("Jane", saved.FirstMidName);
        Assert.Equal("Doe", saved.LastName);
        Assert.Equal(new DateTime(2021, 1, 15), saved.EnrollmentDate);
    }

    #endregion

    #region Edit GET

    [Fact]
    public void Edit_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_ValidId_ReturnsViewWithStudent()
    {
        _context.Students.Add(new Student
        {
            ID = 1, FirstMidName = "Carson", LastName = "Alexander",
            EnrollmentDate = DateTime.Parse("2020-01-01")
        });
        _context.SaveChanges();

        var result = _controller.Edit(1);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal("Carson", model.FirstMidName);
    }

    #endregion

    #region Edit POST

    [Fact]
    public void EditPost_ValidStudent_RedirectsToIndex()
    {
        _context.Students.Add(new Student
        {
            ID = 1, FirstMidName = "Carson", LastName = "Alexander",
            EnrollmentDate = DateTime.Parse("2020-01-01")
        });
        _context.SaveChanges();
        _context.ChangeTracker.Clear();

        var student = new Student
        {
            ID = 1, FirstMidName = "Carson Updated", LastName = "Alexander",
            EnrollmentDate = new DateTime(2020, 9, 1)
        };

        var result = _controller.Edit(student);
        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void EditPost_InvalidDate_ReturnsView()
    {
        var student = new Student
        {
            ID = 1, FirstMidName = "Test", LastName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Edit(student);
        Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void EditPost_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            ID = 1, FirstMidName = "Test",
            EnrollmentDate = new DateTime(2020, 9, 1)
        };

        var result = _controller.Edit(student);
        Assert.IsType<ViewResult>(result);
    }

    #endregion

    #region Delete GET

    [Fact]
    public void Delete_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Delete_ValidId_ReturnsViewWithStudent()
    {
        _context.Students.Add(new Student
        {
            ID = 1, FirstMidName = "Carson", LastName = "Alexander",
            EnrollmentDate = DateTime.Parse("2020-01-01")
        });
        _context.SaveChanges();

        var result = _controller.Delete(1);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal("Carson", model.FirstMidName);
    }

    #endregion

    #region DeleteConfirmed

    [Fact]
    public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
    {
        _context.Students.Add(new Student
        {
            ID = 1, FirstMidName = "Carson", LastName = "Alexander",
            EnrollmentDate = DateTime.Parse("2020-01-01")
        });
        _context.SaveChanges();

        var result = _controller.DeleteConfirmed(1);
        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.Empty(_context.Students);
    }

    [Fact]
    public void DeleteConfirmed_VerifyStudentRemoved()
    {
        _context.Students.Add(new Student
        {
            ID = 5, FirstMidName = "Test", LastName = "Student",
            EnrollmentDate = DateTime.Parse("2020-01-01")
        });
        _context.SaveChanges();

        _controller.DeleteConfirmed(5);
        Assert.Null(_context.Students.Find(5));
    }

    #endregion
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly CoursesController _controller;
    private readonly SchoolContext _context;
    private readonly Mock<IWebHostEnvironment> _envMock;
    private readonly Mock<ILogger<CoursesController>> _loggerMock;

    public CoursesControllerTests()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _envMock = new Mock<IWebHostEnvironment>();
        _envMock.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
        _envMock.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
        _loggerMock = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    #region Index

    [Fact]
    public void Index_ReturnsViewResult_WithListOfCourses()
    {
        TestHelpers.SeedCourses(_context);
        var result = _controller.Index();
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<List<Course>>(viewResult.Model);
        Assert.Equal(2, model.Count);
    }

    [Fact]
    public void Index_NoCourses_ReturnsEmptyList()
    {
        var result = _controller.Index();
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<List<Course>>(viewResult.Model);
        Assert.Empty(model);
    }

    #endregion

    #region Details

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithCourse()
    {
        TestHelpers.SeedCourses(_context);
        var result = _controller.Details(1050);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal("Chemistry", model.Title);
        Assert.Equal(1050, model.CourseID);
    }

    #endregion

    #region Create GET

    [Fact]
    public void Create_Get_ReturnsViewResult()
    {
        TestHelpers.SeedDepartments(_context);
        var result = _controller.Create();
        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.IsType<Course>(viewResult.Model);
    }

    #endregion

    #region Create POST

    [Fact]
    public void CreatePost_ValidCourse_NoImage_RedirectsToIndex()
    {
        TestHelpers.SeedDepartments(_context);
        var course = new Course { CourseID = 9999, Title = "Test Course", Credits = 3, DepartmentID = 1 };

        var result = _controller.Create(course, null!);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.Single(_context.Courses);
    }

    [Fact]
    public void CreatePost_InvalidModelState_ReturnsView()
    {
        TestHelpers.SeedDepartments(_context);
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 1, DepartmentID = 1 };

        var result = _controller.Create(course, null!);
        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void CreatePost_InvalidFileExtension_ReturnsViewWithError()
    {
        TestHelpers.SeedDepartments(_context);
        var course = new Course { CourseID = 1, Title = "Test", Credits = 3, DepartmentID = 1 };

        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("test.txt");
        fileMock.Setup(f => f.Length).Returns(100);

        var result = _controller.Create(course, fileMock.Object);
        Assert.IsType<ViewResult>(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void CreatePost_FileTooLarge_ReturnsViewWithError()
    {
        TestHelpers.SeedDepartments(_context);
        var course = new Course { CourseID = 1, Title = "Test", Credits = 3, DepartmentID = 1 };

        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("test.jpg");
        fileMock.Setup(f => f.Length).Returns(6 * 1024 * 1024);

        var result = _controller.Create(course, fileMock.Object);
        Assert.IsType<ViewResult>(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void CreatePost_ValidImage_SavesFileAndRedirects()
    {
        TestHelpers.SeedDepartments(_context);
        var course = new Course { CourseID = 1, Title = "Test", Credits = 3, DepartmentID = 1 };

        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("test.jpg");
        fileMock.Setup(f => f.Length).Returns(1024);
        fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));

        var result = _controller.Create(course, fileMock.Object);
        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.NotNull(_context.Courses.Find(1)!.TeachingMaterialImagePath);
    }

    [Theory]
    [InlineData(".jpg")]
    [InlineData(".jpeg")]
    [InlineData(".png")]
    [InlineData(".gif")]
    [InlineData(".bmp")]
    public void CreatePost_AllowedExtensions_Accepted(string extension)
    {
        TestHelpers.SeedDepartments(_context);
        var courseId = Math.Abs(extension.GetHashCode()) % 10000 + 100;
        var course = new Course { CourseID = courseId, Title = "Test", Credits = 3, DepartmentID = 1 };

        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns($"test{extension}");
