using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class InstructorsControllerTests : IDisposable
{
    private readonly InstructorsController _controller;
    private readonly SchoolContext _context;

    public InstructorsControllerTests()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new InstructorsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedInstructorsWithCourses()
    {
        var dept = new Department { DepartmentID = 1, Name = "Engineering", Budget = 350000, StartDate = DateTime.Parse("2007-09-01") };
        _context.Departments.Add(dept);

        var course1 = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1, Enrollments = new List<Enrollment>() };
        var course2 = new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1, Enrollments = new List<Enrollment>() };
        _context.Courses.AddRange(course1, course2);

        var instructor = new Instructor
        {
            ID = 10, FirstMidName = "Kim", LastName = "Abercrombie",
            HireDate = DateTime.Parse("1995-03-11"),
            CourseAssignments = new List<CourseAssignment> { new CourseAssignment { CourseID = 1050, InstructorID = 10 } },
            OfficeAssignment = new OfficeAssignment { InstructorID = 10, Location = "Smith 17" }
        };
        _context.Instructors.Add(instructor);

        var instructor2 = new Instructor
        {
            ID = 11, FirstMidName = "Fadi", LastName = "Fakhouri",
            HireDate = DateTime.Parse("2002-07-06"),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.Add(instructor2);
        _context.SaveChanges();
    }

    #region Index

    [Fact]
    public void Index_NoParams_ReturnsViewWithInstructors()
    {
        SeedInstructorsWithCourses();
        var result = _controller.Index(null, null);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(viewResult.Model);
        Assert.Equal(2, model.Instructors.Count());
    }

    [Fact]
    public void Index_WithInstructorId_ShowsCourses()
    {
        SeedInstructorsWithCourses();
        var result = _controller.Index(10, null);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(viewResult.Model);
        Assert.NotNull(model.Courses);
        Assert.Single(model.Courses);
        Assert.Equal("Chemistry", model.Courses.First().Title);
    }

    [Fact]
    public void Index_WithInstructorAndCourseId_ShowsEnrollments()
    {
        SeedInstructorsWithCourses();
        _context.Students.Add(new Student { ID = 1, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2020-01-01") });
        _context.Enrollments.Add(new Enrollment { EnrollmentID = 1, CourseID = 1050, StudentID = 1, Grade = Grade.A });
        _context.SaveChanges();

        var result = _controller.Index(10, 1050);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(viewResult.Model);
        Assert.NotNull(model.Enrollments);
        Assert.Single(model.Enrollments);
    }

    [Fact]
    public void Index_EmptyDatabase_ReturnsEmptyInstructorList()
    {
        var result = _controller.Index(null, null);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(viewResult.Model);
        Assert.Empty(model.Instructors);
    }

    #endregion

    #region Details

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
        SeedInstructorsWithCourses();
        var result = _controller.Details(10);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.Equal("Kim", model.FirstMidName);
        Assert.Equal("Abercrombie", model.LastName);
    }

    #endregion

    #region Create GET

    [Fact]
    public void Create_Get_ReturnsViewResult()
    {
        SeedInstructorsWithCourses();
        var result = _controller.Create();
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.NotNull(model.CourseAssignments);
        Assert.Empty(model.CourseAssignments);
    }

    #endregion

    #region Create POST

    [Fact]
    public void CreatePost_ValidInstructor_NoSelectedCourses_RedirectsToIndex()
    {
        SeedInstructorsWithCourses();
        var instructor = new Instructor
        {
            FirstMidName = "New", LastName = "Instructor",
            HireDate = DateTime.Parse("2020-01-01")
        };

        var result = _controller.Create(instructor, null!);
        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void CreatePost_ValidInstructor_WithSelectedCourses_RedirectsToIndex()
    {
        SeedInstructorsWithCourses();
        var instructor = new Instructor
        {
            FirstMidName = "New", LastName = "Instructor",
            HireDate = DateTime.Parse("2020-01-01")
        };

        var result = _controller.Create(instructor, new[] { "1050", "4022" });
        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void CreatePost_WithSelectedCourses_CreatesCourseAssignments()
    {
        SeedInstructorsWithCourses();
        var instructor = new Instructor
        {
            FirstMidName = "New", LastName = "Instructor",
            HireDate = DateTime.Parse("2020-01-01")
        };

        _controller.Create(instructor, new[] { "1050" });

        var savedInstructor = _context.Instructors.Where(i => i.LastName == "Instructor").First();
        Assert.NotNull(savedInstructor.CourseAssignments);
        Assert.Single(savedInstructor.CourseAssignments);
    }

    [Fact]
    public void CreatePost_InvalidModelState_ReturnsView()
    {
        SeedInstructorsWithCourses();
        _controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            FirstMidName = "Test", HireDate = DateTime.Parse("2020-01-01"),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _controller.Create(instructor, null!);
        Assert.IsType<ViewResult>(result);
    }

    #endregion

    #region Edit GET

    [Fact]
    public void Edit_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_ValidId_ReturnsViewWithInstructor()
    {
        SeedInstructorsWithCourses();
        var result = _controller.Edit(10);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.Equal("Kim", model.FirstMidName);
    }

    #endregion

    #region Delete GET

    [Fact]
    public void Delete_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Delete_ValidId_ReturnsViewWithInstructor()
    {
        SeedInstructorsWithCourses();
        var result = _controller.Delete(10);
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.Equal("Abercrombie", model.LastName);
    }

    #endregion

    #region DeleteConfirmed

    [Fact]
    public void DeleteConfirmed_ValidId_RemovesInstructorAndRedirects()
    {
        SeedInstructorsWithCourses();
        var result = _controller.DeleteConfirmed(10);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.Null(_context.Instructors.Find(10));
    }

    [Fact]
    public void DeleteConfirmed_InstructorIsDeptAdmin_NullsDepartmentInstructorID()
    {
        SeedInstructorsWithCourses();
        var dept = _context.Departments.Find(1)!;
        dept.InstructorID = 10;
        _context.SaveChanges();

        _controller.DeleteConfirmed(10);

        var updatedDept = _context.Departments.Find(1)!;
        Assert.Null(updatedDept.InstructorID);
    }

    [Fact]
    public void DeleteConfirmed_InstructorNotDeptAdmin_DoesNotAffectDepartments()
    {
        SeedInstructorsWithCourses();
        // dept admin is not instructor 11
        var dept = _context.Departments.Find(1)!;
        dept.InstructorID = 10;
        _context.SaveChanges();

        _controller.DeleteConfirmed(11);

        var updatedDept = _context.Departments.Find(1)!;
        Assert.Equal(10, updatedDept.InstructorID);
    }

    #endregion
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class NotificationsControllerTests : IDisposable
{
    private readonly NotificationsController _controller;
    private readonly SchoolContext _context;

    public NotificationsControllerTests()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new NotificationsController(_context);
        var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void GetNotifications_NoNotifications_ReturnsJsonResult()
    {
        var result = _controller.GetNotifications();
        Assert.IsType<JsonResult>(result);
        Assert.NotNull(result.Value);
    }

    [Fact]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        var service = new NotificationService();
        service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
        service.SendNotification("Course", "2", "Chemistry", EntityOperation.UPDATE);

        var result = _controller.GetNotifications();
        Assert.IsType<JsonResult>(result);
        Assert.NotNull(result.Value);
    }

    [Fact]
    public void MarkAsRead_ReturnsJsonResult()
    {
        var result = _controller.MarkAsRead(1);
        Assert.IsType<JsonResult>(result);
        Assert.NotNull(result.Value);
    }

    [Fact]
    public void Index_ReturnsViewResult()
    {
        var result = _controller.Index();
        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void GetNotifications_ReturnsSuccessProperty()
    {
        var result = _controller.GetNotifications();
        var value = result.Value;
        Assert.NotNull(value);
        // Verify the anonymous type has expected properties
        var type = value.GetType();
        var successProp = type.GetProperty("success");
        Assert.NotNull(successProp);
        Assert.True((bool)successProp.GetValue(value)!);
    }

    [Fact]
    public void GetNotifications_LimitsTo10()
    {
        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Student", i.ToString(), $"Student {i}", EntityOperation.CREATE);
        }

        var result = _controller.GetNotifications();
        var value = result.Value;
        Assert.NotNull(value);
        var countProp = value.GetType().GetProperty("count");
        Assert.NotNull(countProp);
        var count = (int)countProp.GetValue(value)!;
        Assert.Equal(10, count);
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class TestableController : BaseController
{
    public TestableController(SchoolContext context) : base(context) { }

    public void InvokeSendEntityNotification(string entityType, string entityId, EntityOperation operation)
    {
        SendEntityNotification(entityType, entityId, operation);
    }

    public void InvokeSendEntityNotification(string entityType, string entityId, string? displayName, EntityOperation operation)
    {
        SendEntityNotification(entityType, entityId, displayName, operation);
    }

    public SchoolContext GetDb() => db;
    public NotificationService GetNotificationService() => notificationService;
}

public class BaseControllerTests : IDisposable
{
    private readonly TestableController _controller;
    private readonly SchoolContext _context;

    public BaseControllerTests()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new TestableController(_context);
        var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Constructor_SetsDbContext()
    {
        Assert.NotNull(_controller.GetDb());
        Assert.Same(_context, _controller.GetDb());
    }

    [Fact]
    public void Constructor_CreatesNotificationService()
    {
        Assert.NotNull(_controller.GetNotificationService());
    }

    [Fact]
    public void SendEntityNotification_TwoParams_DoesNotThrow()
    {
        var ex = Record.Exception(() =>
            _controller.InvokeSendEntityNotification("Student", "1", EntityOperation.CREATE));
        Assert.Null(ex);
    }

    [Fact]
    public void SendEntityNotification_ThreeParams_DoesNotThrow()
    {
        var ex = Record.Exception(() =>
            _controller.InvokeSendEntityNotification("Student", "1", "Test Student", EntityOperation.CREATE));
        Assert.Null(ex);
    }

    [Fact]
    public void SendEntityNotification_EnqueuesNotification()
    {
        _controller.InvokeSendEntityNotification("Course", "42", "Chemistry", EntityOperation.UPDATE);
        var svc = new NotificationService();
        var notification = svc.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Course", notification.EntityType);
        Assert.Equal("42", notification.EntityId);
        Assert.Contains("updated", notification.Message);
    }

    [Fact]
    public void SendEntityNotification_UsesSystemAsDefaultUser()
    {
        _controller.InvokeSendEntityNotification("Student", "1", EntityOperation.CREATE);
        var svc = new NotificationService();
        var notification = svc.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void Dispose_DisposesResources()
    {
        var controller = new TestableController(TestHelpers.CreateInMemoryContext());
        var ex = Record.Exception(() => controller.Dispose());
        Assert.Null(ex);
    }

    [Fact]
    public void SendEntityNotification_NullDisplayName_DoesNotThrow()
    {
        var ex = Record.Exception(() =>
            _controller.InvokeSendEntityNotification("Student", "1", null, EntityOperation.DELETE));
        Assert.Null(ex);
    }
}

