        Assert.Equal("Student", student.LastName);
    }

    [Fact]
    public void Context_CanAddAndRetrieveCourse()
    {
        _context.Departments.Add(new Department { DepartmentID = 1, Name = "Test", Budget = 1000, StartDate = DateTime.Now });
        _context.SaveChanges();
        _context.Courses.Add(new Course { CourseID = 1, Title = "Test Course", Credits = 3, DepartmentID = 1 });
