    public void Context_CanAddAndRetrieveEnrollment()
    {
        _context.Students.Add(new Student { ID = 1, FirstMidName = "A", LastName = "B", EnrollmentDate = DateTime.Now });
        _context.Departments.Add(new Department { DepartmentID = 1, Name = "Test", Budget = 1000, StartDate = DateTime.Now });
        _context.Courses.Add(new Course { CourseID = 100, Title = "C", Credits = 3, DepartmentID = 1 });
        _context.SaveChanges();

        _context.Enrollments.Add(new Enrollment { CourseID = 100, StudentID = 1, Grade = Grade.A });
        _context.SaveChanges();

        var enrollment = _context.Enrollments.First();
        Assert.Equal(Grade.A, enrollment.Grade);
        Assert.Equal(100, enrollment.CourseID);
        Assert.Equal(1, enrollment.StudentID);
    }

