+
+namespace ContosoUniversity.Tests.Data;
+
+public class SchoolContextFactoryTests
+{
+    [Fact]
+    public void Create_ReturnsSchoolContext_WhenConnectionStringExists()
+    {
+        var inMemorySettings = new Dictionary<string, string?>
+        {
+            {"ConnectionStrings:DefaultConnection", "Server=(localdb)\\mssqllocaldb;Database=TestDb;Trusted_Connection=True;"}
+        };
+        var configuration = new ConfigurationBuilder()
+            .AddInMemoryCollection(inMemorySettings)
+            .Build();
+
+        var context = SchoolContextFactory.Create(configuration);
+
+        Assert.NotNull(context);
+        Assert.IsType<SchoolContext>(context);
+        context.Dispose();
+    }
+
+    [Fact]
+    public void Create_ReturnsDistinctContextInstances()
+    {
+        var inMemorySettings = new Dictionary<string, string?>
+        {
+            {"ConnectionStrings:DefaultConnection", "Server=(localdb)\\mssqllocaldb;Database=TestDb;Trusted_Connection=True;"}
+        };
+        var configuration = new ConfigurationBuilder()
+            .AddInMemoryCollection(inMemorySettings)
+            .Build();
+
+        var context1 = SchoolContextFactory.Create(configuration);
+        var context2 = SchoolContextFactory.Create(configuration);
+
+        Assert.NotSame(context1, context2);
+        context1.Dispose();
+        context2.Dispose();
+    }
+}
