+        {
+            Instructors = new List<Instructor>
+            {
+                new Instructor { FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("2020-01-01"), CourseAssignments = new List<CourseAssignment>() }
+            },
+            Courses = new List<Course>
+            {
+                new Course { CourseID = 1, Title = "Chemistry", Credits = 3 }
+            },
+            Enrollments = new List<Enrollment>
+            {
+                new Enrollment { EnrollmentID = 1, CourseID = 1, StudentID = 1, Grade = Grade.A }
+            }
+        };
